import 'package:cloud_firestore/cloud_firestore.dart'; import '../../../../core/constants/firestore_collections.dart'; import '../../../../core/services/firebase/firestore_service.dart'; import '../../domain/entities/app_notification.dart'; import '../../domain/repositories/notification_repository.dart';
class NotificationRepositoryImpl implements NotificationRepository{final FirestoreService fs; const NotificationRepositoryImpl(this.fs); CollectionReference<Map<String,dynamic>> get notifications=>fs.collection(FirestoreCollections.notifications); @override Stream<List<AppNotification>> watchNotifications(String userId)=>notifications.where('userId',isEqualTo:userId).orderBy('createdAt',descending:true).snapshots().map((s)=>s.docs.map((d)=>AppNotification.fromMap(d.id,d.data())).toList()); @override Future<int> unreadCount(String userId) async=>(await notifications.where('userId',isEqualTo:userId).where('isRead',isEqualTo:false).count().get()).count??0; @override Future<void> markAsRead(String id)=>notifications.doc(id).update({'isRead':true}); @override Future<void> markAllAsRead(String userId) async{final s=await notifications.where('userId',isEqualTo:userId).where('isRead',isEqualTo:false).get(); final batch=fs.batch(); for(final d in s.docs){batch.update(d.reference,{'isRead':true});} await batch.commit();} @override Future<void> createNotification(AppNotification n)=>notifications.doc(n.id.isEmpty?null:n.id).set({...n.toMap(),'createdAt':FieldValue.serverTimestamp()});}
